  const layout = useLayout(args);
  const accountMenu = useAccountMenu({
    accountId: 'diaspora'
  });
  const globalMenu = useGlobalMenu({
    accountId: 'diaspora'
  });
  const accountSelector: AccountSelectorProps = {
    accountMenu: accountMenu
  };
  const sidebar = {
    ...layout.sidebar,
    sticky: true
  };
  const header = {
    ...layout.header,
    accountSelector: accountSelector,
    globalMenu: globalMenu
  };
  const breadcrumbs = {
    ariaLabel: 'Du er her:',
    items: [{
      label: 'Innboks',
      href: '#'
    }, {
      label: 'Arkiv',
      href: '#'
    }]
  };
  const toolbar = {
    accountMenu: {
      label: accountMenu?.currentAccount?.title,
      items: accountMenu?.items,
      searchable: true
    },
    search: {
      placeholder: 'Søk',
      collapsible: true
    }
  };
  return <RootProvider>
      <Layout {...args} {...layout} sidebar={sidebar} header={header} breadcrumbs={breadcrumbs}>
        <PageBase>
          <Heading size="xl">Page title</Heading>
          <Toolbar {...toolbar} />
          <DialogList {...inboxSection} />
        </PageBase>
      </Layout>
    </RootProvider>;
